use std::fmt;
use std::error::Error;

#[derive(Debug)]
struct PathfindingError { 
    message: String
}

impl fmt::Display for PathfindingError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Pathfinding failed: {}", self.message)
    }
}

impl Error for PathfindingError {} 

fn calculate_path(start: (i32, i32), end: (i32, i32)) -> Result<Vec<(i32, i32)>, Box<dyn Error>> {
    if start.0 < 0 || end.0 < 0 {
        return Err(Box::new(PathfindingError { message: "Coordinates cannot be negative".to_string() }));
    }

    if (start.0 - end.0).abs() > 100 || (start.1 - end.1).abs() > 100 {
        return Err(Box::new(PathfindingError { message: "Target is too far away to calculate path".to_string() }));
    }

    let mut path = vec![(start.0, start.1)];
    path.push((end.0, end.1));

    Ok(path)
}

fn main() {
    match calculate_path((10, 20), (50, 60)) {
        Ok(path) => println!("Path calculated successfully: {:?}", path),
        Err(e) => eprintln!("Caught an error during pathfinding: {}", e),
    }

    match calculate_path((10, 20), (-5, 60)) {
        Ok(_) => (), 
        Err(e) => eprintln!("Caught expected error on bad input: {}", e),
    }
}
